{
  "name": "Oregon Health Plan (OHP)",
  "eligibility": {
    "age": 65,
    "income_limits": "For elderly (65+), eligibility is primarily through OSIPM (Oregon Supplemental Income Program-Medical), part of OHP for long-term care. Income limits for Aged, Blind, and Disabled (ABD) category in 2025: $967/month for an individual, $1,450/month for a couple (based on Federal Benefit Rate). General OHP Plus for adults 19-64 is up to 133% FPL (~$1,507/month single, $3,076 family of 4; updated annually). OHP Bridge for adults 19-65: 139-200% FPL (e.g., single: up to ~$2,674/month). Limits vary by household size and program; full table example from CareOregon (approximate monthly, subject to annual FPL updates): Family of 1 - OHP Plus $1,800, Bridge $2,674; Family of 2 - higher accordingly. Elderly long-term care has specific thresholds; apply to confirm.[3][4][5]",
    "asset_limits": "OSIPM for elderly long-term care has asset limits (not detailed in exact dollar amounts here, but typically Medicaid-standard ~$2,000 individual/$3,000 couple excluding home, one car, personal items, burial plots). Ways to qualify if over limits via spend-down or exemptions. What counts: cash, bank accounts, investments; exempt: primary home (if intent to return), one vehicle, household goods.[3]",
    "other_requirements": ["Oregon resident", "U.S. citizen or eligible immigration status (as of July 2023, some benefits regardless of status)", "For long-term care: need for nursing home (30+ days), assisted living, adult foster care, or home-based services; meet disability/blind criteria if applicable", "Not eligible if access to affordable insurance (for Bridge)", "Verification of income/resources required post-application[1][3][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Comprehensive no-cost coverage: medical, dental, prescription drugs, behavioral health. For elderly/long-term care via OSIPM: nursing home care, assisted living, adult foster care, home health/non-medical support services to stay at home. Nursing home residents keep ~$77/month personal needs allowance ($90 with VA pension). Covers frail seniors' needs.[3][4][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: ONE.Oregon.gov or Benefits.Oregon.gov", "Phone: 1-800-699-9075 (ONE Customer Service); for older adults/disabilities: 1-855-ORE-ADRC (855-673-2372)", "Mail: OHP Customer Service, P.O. Box (details on site)", "In-person: Local Oregon Department of Human Services (ODHS) office or Aging and Disability Resource Connection (ADRC)"],
    "processing_time": "Not specified in sources; apply anytime, eligibility determined after submission.",
    "waitlist": null,
    "forms": ["Online application via ONE.Oregon.gov; paper application mailed to OHP Customer Service"],
    "documents": ["Proof of income (pay stubs, tax returns), identity (ID/driver's license), residency, citizenship/immigration status, assets/resources, disability/medical records if applicable, Medicare info if dual-eligible[3][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered statewide by ODHS, but local offices handle in-person; potential regional differences in providers, wait times for long-term care services (not detailed)[3][6]",
    "offices_or_providers": ["Local ODHS offices; ADRC centers; CareOregon as coordinated care organization in some regions"]
  },
  "official_source": "https://www.oregon.gov/oha/hsd/ohp/pages/apply.aspx",
  "gotchas": ["Multiple OHP tiers (Plus, Bridge, OSIPM for elderly LTC) with different limits—elderly often need OSIPM, not standard Plus; ABD has stricter FBR-based limits vs. FPL; asset tests apply for LTC, not always for general OHP; income calculated current/next/annual depending on program; Medicare dual-eligibility affects drug coverage (OHP Limited Drug); spend-down options if over limits; FPL updates annually—2026 guide referenced but limits shown through 2025; apply even if over limits as exemptions/strategies exist[1][3][4][9]"],
  "data_shape_notes": "benefits scale by household size and tier (OHP Plus/Bridge/OSIPM); income uses FPL or FBR; long-term care for elderly via OSIPM with asset tests and spend-down; statewide but local ODHS/ADRC handling"
}

{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Household gross income at or below 200% of the federal poverty level. Income includes all household members before payroll deductions. Specific dollar amounts vary annually and by household size; contact local agency for current table as 2025-26 guidelines not detailed in sources. Priority given to seniors (60+), people with disabilities, households with children under 6, high energy users, and high energy burden households.",
    "asset_limits": "No asset limits mentioned.",
    "other_requirements": ["Renters need landlord approval.", "Homeowners or renters in single-family homes, mobile homes, or multifamily (with approval).", "Must meet LIHEAP eligibility or similar for certification in some cases."]
  },
  "benefits": {
    "type": "service",
    "value": "Free weatherization services including: ceiling/wall/floor insulation, air sealing/infiltration reduction, furnace/heating system repair or replacement, heating duct improvements, energy-related minor home repairs, base-load measures, health/safety repairs, ventilation, LED bulbs, and energy conservation education. Services determined by energy audit for cost-effectiveness.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Community Action Agency (CAA) or subgrantee by phone or in-person.", "Examples: Clackamas County (phone not specified in results), Marion/Polk (503-361-8740 press 0), Multnomah (503-282-6309), Washington (503-640-3497), Yamhill (503-472-0457). Portland homeowners: Community Energy Project (phone not specified). Lane County: Homes for Good. Mid-Willamette: MWVCAA.", "Mail or in-person: Varies by local agency, e.g., NeighborImpact application packet.", "No statewide online application; agency-specific forms like NeighborImpact Weatherization Application, Supplemental form, Declaration of Household Income."],
    "processing_time": "Not specified; agency contacts eligible households to schedule energy audit after application.",
    "waitlist": "Households may be placed on a waiting service list after contacting local agency.",
    "forms": ["Weatherization Application", "Weatherization Supplemental form", "Declaration of Household Income form"],
    "documents": ["Proof of income (paycheck stubs for 60 days, Social Security/SSDI/SSI benefit letter).", "Utility bills (electric, gas if applicable).", "Proof of ID for members 18+ (Driver’s License, Passport, etc.).", "Proof of ownership/rental (mortgage statement, deed, lease)."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered locally; available to renters/homeowners statewide.",
    "regional_variations": "Administered by local community action agencies, senior centers, housing authorities; different providers, phone numbers, and waitlists by county/region. Examples: NeighborImpact (Deschutes?), Homes for Good (Lane County), MWVCAA (Mid-Willamette), county-specific CAAs.",
    "offices_or_providers": ["Local Community Action Agencies by county", "Oregon Housing and Community Services (OHCS) oversees"]
  },
  "official_source": "https://www.oregon.gov/ohcs/energy-weatherization/Pages/default.aspx",
  "gotchas": ["Priority populations (elderly 60+, disabled, young children) get preference; non-priority may face longer waits.", "Renters must get landlord permission.", "Services based on energy audit cost-effectiveness, not all measures guaranteed.", "Income at exactly 200% FPL qualifies; gross income before deductions.", "May certify eligibility via LIHEAP or other programs without re-verifying income.", "Waiting lists common due to funding limits."],
  "data_shape_notes": "Administered by county-specific subgrantees with varying contacts; priority tiers affect service timing; income fixed at 200% FPL with no asset test; services vary by audit results"
}

{
  "name": "Senior Health Insurance Benefits Assistance (SHIBA)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Oregon residents with Medicare regardless of income.",
    "asset_limits": "No asset limits; no asset test applies.",
    "other_requirements": ["Must be an Oregon resident with Medicare.", "Includes people age 65+ and individuals ages 18-64 with disabilities who have Medicare."]
  },
  "benefits": {
    "type": "service",
    "value": "Free, objective, unbiased counseling and education on Medicare benefits, options, billing issues, appeals, plan comparisons, rights, and identifying Medicare fraud, error, or abuse. Provided one-on-one by trained volunteer counselors via phone, in-person, online, or public events. No financial aid, healthcare services, or fixed hours/dollar amounts.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-722-4134 (toll-free statewide hotline; enter zip code for local routing)", "Website: https://shiba.oregon.gov/get-help/pages/helpnearyou.aspx (find local counseling sites)", "Email: shiba.oregon@odhs.oregon.gov or online contact form at https://shiba.oregon.gov/get-help/pages/connect-with-us.aspx", "In-person: Local offices and events (search by zip code on site; examples include Clackamas: 503-655-8269, Multnomah: 503-988-3646)", "Public events: Medicare presentations at libraries and offices (check local calendars)"],
    "processing_time": "Immediate counseling available by phone or appointment; no formal application processing.",
    "waitlist": null,
    "forms": ["No specific application forms required for receiving help; volunteer applicants complete SHIBA Volunteer Application."],
    "documents": ["No documents needed to receive counseling; bring Medicare card, current plan details, bills, or questions for personalized assistance."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all Oregon counties.",
    "regional_variations": "Delivered through statewide network of local offices, sponsors, and volunteers with county-specific phone lines, events, and sites (e.g., Clackamas, Multnomah); no differences in services, but local availability and scheduling varies.",
    "offices_or_providers": ["Statewide office: Department of Consumer and Business Services, 350 Winter Street NE Room 330, Salem OR 97309-0405", "Local sites searchable by zip code at https://shiba.oregon.gov/get-help/pages/helpnearyou.aspx"]
  },
  "official_source": "https://shiba.oregon.gov",
  "gotchas": ["Not a benefits-paying program—provides only free counseling, not financial assistance, healthcare, or enrollment on your behalf.", "Requires Medicare enrollment; helps with Medicare questions but does not cover non-Medicare insurance.", "Services rely on volunteer availability; during peak times like Open Enrollment (Oct 15-Dec 7), schedule appointments early.", "People with Medicaid/OHP changes post-COVID emergency may need to transition to Medicare and use SHIBA for guidance.", "Confidential but assessors review resources/needs during sessions."],
  "data_shape_notes": "no income or asset test; volunteer-based counseling service scaled statewide via local sites with no fixed benefits value"
}

{
  "name": "Oregon Senior Tuition Waiver (OSU/UO Audit Program)",
  "eligibility": {
    "age": 65,
    "income_limits": "No income limits or asset limits apply. No variations by household size.",
    "asset_limits": "No asset limits. No assets counted or exempted as none required.",
    "other_requirements": ["Oregon resident", "Must audit classes (no credit or grade earned)", "Instructor permission required", "Space available after paying students register", "Not for limited entry programs (e.g., Nursing, Aquarium Science)", "Maximum 8 credits per term at some colleges"]
  },
  "benefits": {
    "type": "in_kind",
    "value": "100% tuition waiver for audited credit classes. Does not cover student fees, course fees, lab fees, or materials. Up to 8 credits per term possible.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Varies by institution: e.g., at Oregon Coast CC - online application, email instructor (cc Registrar@OregonCoast.edu), submit Senior Waiver form online; at UO - submit Auditor Registration Form and Staff Tuition Benefit form through Registrar's Office (specific URLs/forms per school)", "Contact specific college registrar for details (no central phone listed)"],
    "processing_time": "Registration after first day of class if approved; instructor response time varies",
    "waitlist": "No formal waitlist; space-available only after paying students",
    "forms": ["Senior Waiver form (Oregon Coast CC)", "Auditor Registration Form (UO)", "Institution-specific forms"],
    "documents": ["Proof of age (e.g., ID showing 65+)", "Proof of Oregon residency", "Online application if new student"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available at public universities (e.g., OSU, UO, PSU) and community colleges statewide",
    "regional_variations": "Process varies by institution (e.g., email instructor at OCCC, forms at UO); some community colleges may have age 60+ (e.g., OCCC), but statute mandates 65+ for universities/community colleges",
    "offices_or_providers": ["University of Oregon Registrar", "Oregon State University (contact registrar)", "Community college registrars (e.g., Oregon Coast CC Registrar@OregonCoast.edu)"]
  },
  "official_source": "https://www.oregonlegislature.gov/bills_laws/ors/ors352.html (ORS 352.303 for universities); https://www.oregonlegislature.gov/bills_laws/ors/ors341.html (ORS 341.518 for community colleges)",
  "gotchas": ["No credit earned - purely audit/no grade", "Fees still apply (mandatory, course, lab)", "Instructor must approve; seats only if available post-regular registration", "Cannot displace paying students or enter limited programs", "Some colleges cap at 8 credits/term", "Community colleges may allow 60+ locally, but state law 65+ for uniformity"],
  "data_shape_notes": "Statewide but institution-administered; audit-only (no credit); no financial tests; space/instructor gatekept; age 65+ per statute (some colleges 60+)"
}
